@import "tailwindcss";

/* Cadence design tokens — "Porcelain Ledger".
   Brand: ink-first porcelain neutrals (Mercury-grade restraint); green is
   demoted to data only (progress meters, verified state, one hairline on the
   hero stat). Status colors are reserved exclusively for document/deadline
   state (missing = amber, overdue = red, in review = blue, verified = green).
   Light theme only. */

@theme inline {
  --font-sans: var(--font-inter), ui-sans-serif, system-ui, sans-serif;
  --font-mono: var(--font-spline-mono), ui-monospace, "SF Mono", monospace;
}

@theme {
  /* Brand — ledger green, data-only */
  --color-evergreen-50: #e7f4ee;
  --color-evergreen-100: #d3ebdf;
  --color-evergreen-200: #abd8c4;
  --color-evergreen-300: #7cbfa2;
  --color-evergreen-400: #4c9f7d;
  --color-evergreen-500: #1e7f53;
  --color-evergreen-600: #196b46;
  --color-evergreen-700: #15573a;
  --color-evergreen-800: #124630;
  --color-evergreen-900: #0e3726;
  --color-evergreen-950: #08211a;

  /* Porcelain neutrals & ink */
  --color-surface: #fbfbfa;
  --color-card: #ffffff;
  --color-line: #ecebe8;
  --color-line-strong: #dfddd8;
  --color-ink: #111111;
  --color-ink-soft: #46443f;
  --color-ink-faint: #908c85;

  /* Status — document/deadline state only */
  --color-status-missing: #a16207;
  --color-status-missing-bg: #faf3e3;
  --color-status-overdue: #b0473a;
  --color-status-overdue-bg: #fbede9;
  --color-status-review: #3555c8;
  --color-status-review-bg: #eaeefb;
  --color-status-verified: #1e7f53;
  --color-status-verified-bg: #e7f4ee;

  /* Elevation — barely-there ink */
  --shadow-card: 0 1px 2px rgb(17 17 17 / 0.04);
  --shadow-pop: 0 1px 3px rgb(17 17 17 / 0.05), 0 8px 24px rgb(17 17 17 / 0.07);
}

body {
  background-color: var(--color-surface);
  color: var(--color-ink);
  font-family: var(--font-sans);
  -webkit-font-smoothing: antialiased;
}

::selection {
  background-color: var(--color-evergreen-200);
}

/* Vendo stage approval: the shell's ApprovalCard materializes in-flow
   beneath the generated view (same consent surface as the chat path). */
.cadence-approval-inflow .fl-approval { animation: cadence-approval-in 0.28s cubic-bezier(0.16, 1, 0.3, 1); }
@keyframes cadence-approval-in { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: none; } }
